css:
.d-node {
  opacity: 0; transform: translateY(6px);
  transition: opacity 0.5s cubic-bezier(0.4, 0, 0.2, 1),
              transform 0.5s cubic-bezier(0.4, 0, 0.2, 1);
}
.d-node.visible { opacity: 1; transform: translateY(0); }
.d-node.dimmed { opacity: 0.2; }
.d-node .node-box {
  fill: var(--bg-secondary); stroke: var(--border);
  stroke-width: 1.5; rx: 10; ry: 10; transition: all 0.4s;
}
.d-node.active .node-box {
  stroke: var(--accent-lt); stroke-width: 2;
  filter: drop-shadow(0 0 12px rgba(251, 146, 60, 0.15));
}
.d-node .node-label {
  fill: var(--text); font-family: 'Inter', system-ui, sans-serif;
  font-size: 12.5px; font-weight: 600; text-anchor: middle;
  dominant-baseline: central; transition: fill 0.4s;
}
.d-node.active .node-label { fill: #fff; }
.d-node .node-sublabel {
  fill: var(--text-muted); font-family: 'Inter', system-ui, sans-serif;
  font-size: 10px; text-anchor: middle; dominant-baseline: central;
}
.d-node.active .node-sublabel { fill: var(--text-muted); }
.d-node .node-icon {
  stroke: var(--text-muted); fill: none; stroke-width: 1.5;
  stroke-linecap: round; stroke-linejoin: round;
  transition: stroke 0.4s; overflow: visible;
}
.d-node.active .node-icon { stroke: var(--accent-lt); }
.d-edge { opacity: 0; transition: opacity 0.45s; }
.d-edge.visible { opacity: 1; }
.d-edge.dimmed { opacity: 0.12; }
.d-edge path {
  fill: none; stroke: var(--border); stroke-width: 1.5;
  stroke-linecap: round; transition: stroke 0.4s;
}
.d-edge.active path { stroke: var(--accent-lt); }
.d-edge .edge-label {
  fill: var(--text-muted); font-family: 'Inter', system-ui, sans-serif;
  font-size: 10.5px; text-anchor: middle; dominant-baseline: central;
}
.d-edge .edge-arrow { fill: var(--border); transition: fill 0.4s; }
.d-edge.active .edge-arrow { fill: var(--accent-lt); }
.d-edge.draw path { animation: edgeDraw 0.5s ease-out forwards; }
@keyframes edgeDraw {
  from { stroke-dashoffset: var(--len); }
  to   { stroke-dashoffset: 0; }
}

slides.script:
var show = ['client', 'server', 'auth', 'provider', 'db', 'session', 'e1', 'e2', 'e3', 'e4', 'e5', 'e6'];
var active = [];
var dimmed = [];
var nodeOrder = ['client', 'server', 'auth', 'provider', 'db', 'session'];
var edgeOrder = ['e1', 'e2', 'e3', 'e4', 'e5', 'e6'];
var showSet = {};
var activeSet = {};
var dimmedSet = {};
show.forEach(function(id) { showSet[id] = true; });
active.forEach(function(id) { activeSet[id] = true; });
dimmed.forEach(function(id) { dimmedSet[id] = true; });
var delay = 100;
var stagger = 60;
nodeOrder.forEach(function(id) {
  if (!showSet[id]) return;
  var el = container.querySelector('[data-id="' + id + '"]');
  if (!el) return;
  setTimeout(function() {
    el.classList.add('visible');
    if (activeSet[id]) el.classList.add('active');
    if (dimmedSet[id]) el.classList.add('dimmed');
  }, delay);
  delay += stagger;
});
edgeOrder.forEach(function(id) {
  if (!showSet[id]) return;
  var g = container.querySelector('[data-id="' + id + '"]');
  if (!g) return;
  var path = g.querySelector('path');
  setTimeout(function() {
    g.classList.add('visible');
    if (activeSet[id]) {
      g.classList.add('active');
      path.setAttribute('marker-end', 'url(#arr-a)');
    }
    if (dimmedSet[id]) g.classList.add('dimmed');
    var len = path.getTotalLength();
    path.style.strokeDasharray = len;
    path.style.setProperty('--len', len);
    path.style.strokeDashoffset = '0';
  }, delay);
  delay += stagger * 0.5;
});

